package main

import (
    "fmt"
)

// ---- Interface definition ----
type Damageable interface {
    TakeDamage(int)
    IsAlive() bool
}

type Describable interface {
    Describe() string
}

// ---- Player implements Damageable ----
type Player struct {
    Name   string
    Health int
    MaxHealth int
    Attack int
    Defense int
}

func (p *Player) TakeDamage(damage int) {
    actualDamage := damage - p.Defense/2
    if actualDamage > 0 {
        p.Health -= actualDamage
        if p.Health < 0 {
            p.Health = 0
        }
    }
}

func (p Player) IsAlive() bool {
    return p.Health > 0
}

func (p Player) Describe() string {
    return fmt.Sprintf("Player: %s (HP: %d/%d)", p.Name, p.Health, p.MaxHealth)
}

// ---- Enemy implements Damageable ----
type Enemy struct {
    Name   string
    Health int
    Attack int
    IsBoss bool
}

func (e *Enemy) TakeDamage(damage int) {
    e.Health -= damage
    if e.Health < 0 {
        e.Health = 0
    }
}

func (e Enemy) IsAlive() bool {
    return e.Health > 0
}

func (e Enemy) Describe() string {
    bossStr := ""
    if e.IsBoss {
        bossStr = " (BOSS)"
    }
    return fmt.Sprintf("Enemy: %s%s (HP: %d)", e.Name, bossStr, e.Health)
}

// ---- Interface as parameter ----
func PrintDamageableStatus(d Damageable) {
    if d.IsAlive() {
        fmt.Println("Alive")
    } else {
        fmt.Println("Dead")
    }
}

// ---- Interface with multiple types ----
func PrintDescription(d Describable) {
    fmt.Println(d.Describe())
}

func main() {
    // ---- Both Player and Enemy implement Damageable ----
    hero := &Player{Name: "Hero", Health: 100, MaxHealth: 100, Attack: 20, Defense: 10}
    goblin := &Enemy{Name: "Goblin", Health: 30, Attack: 8, IsBoss: false}

    // ---- Using interface ----
    var d Damageable

    d = hero
    d.TakeDamage(25)
    fmt.Printf("Hero health: %d\n", hero.Health)

    d = goblin
    d.TakeDamage(15)
    fmt.Printf("Goblin health: %d\n", goblin.Health)

    // ---- Interface as parameter ----
    PrintDamageableStatus(hero)
    PrintDamageableStatus(goblin)

    // ---- Multiple interfaces ----
    // Player implements both Damageable and Describable
    PrintDescription(hero)
    PrintDescription(goblin)

    // ---- Empty interface (interface{}) ----
    // interface{} can hold any type
    var anything interface{}

    anything = 42
    fmt.Println("int:", anything)

    anything = "Hello"
    fmt.Println("string:", anything)

    anything = hero
    fmt.Println("struct:", anything)

    // ---- Type assertion ----
    value, ok := anything.(*Player)
    if ok {
        fmt.Println("It's a Player:", value.Name)
    } else {
        fmt.Println("Not a Player")
    }
}

