package main

import "fmt"

type Describable interface {
    Describe() string
}

type Item struct {
    Name  string
    Value int
}

func (i Item) Describe() string {
    return fmt.Sprintf("Item: %s (Value: %d)", i.Name, i.Value)
}

type Player struct {
    Name   string
    Health int
}

func (p Player) Describe() string {
    return fmt.Sprintf("Player: %s (HP: %d)", p.Name, p.Health)
}

func main() {
    things := []Describable{
        Item{Name: "Sword", Value: 50},
        Player{Name: "Hero", Health: 100},
    }

    for _, thing := range things {
        fmt.Println(thing.Describe())
    }
}
